class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        self.handlers: Dict[str, MessageHandler] = {}
        self.running = False
        self._register_default_handlers()

    def _register_default_handlers(self):
        self.register_handler('email', EmailHandler())
        self.register_handler('data_processing', DataProcessingHandler())
        self.register_handler('notification', NotificationHandler())
        self.register_handler('report_generation', ReportGenerationHandler())
        self.register_handler('image_processing', ImageProcessingHandler())
        self.register_handler('database_update', DatabaseUpdateHandler())
        self.register_handler('webhook', WebhookHandler())
        self.register_handler('default', DefaultHandler())

    def register_handler(self, message_type: str, handler: MessageHandler):
        self.handlers[message_type] = handler
        logger.info(f"Registered handler for message type: {message_type}")

    def poll_messages(self) -> list:
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All']
            )
            return response.get('Messages', [])
        except Exception as e:
            logger.error(f"Error polling messages: {e}")
            return []

    def parse_message(self, message: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        try:
            body = message.get('Body', '{}')
            parsed_body = json.loads(body)
            
            if 'Message' in parsed_body:
                parsed_body = json.loads(parsed_body['Message'])
            
            return parsed_body
        except json.JSONDecodeError as e:
            logger.error(f"Error parsing message body: {e}")
            return None

    def process_message(self, message: Dict[str, Any]) -> bool:
        message_id = message.get('MessageId')
        receipt_handle = message.get('ReceiptHandle')
        
        logger.info(f"Processing message: {message_id}")
        
        parsed_data = self.parse_message(message)
        if not parsed_data:
            logger.error(f"Failed to parse message: {message_id}")
            return False
        
        message_type = parsed_data.get('type', 'default')
        logger.info(f"Message type: {message_type}")
        
        handler = self.handlers.get(message_type, self.handlers.get('default'))
        
        try:
            success = handler.handle(parsed_data)
            
            if success:
                self.delete_message(receipt_handle)
                logger.info(f"Successfully processed and deleted message: {message_id}")
                return True
            else:
                logger.warning(f"Handler returned False for message: {message_id}")
                return False
                
        except Exception as e:
            logger.error(f"Error processing message {message_id}: {e}")
            return False

    def delete_message(self, receipt_handle: str):
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
        except Exception as e:
            logger.error(f"Error deleting message: {e}")

    def change_message_visibility(self, receipt_handle: str, timeout: int):
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout
            )
        except Exception as e:
            logger.error(f"Error changing message visibility: {e}")

    def start(self):
        self.running = True
        logger.info(f"Starting SQS worker for queue: {self.queue_url}")
        
        while self.running:
            try:
                messages = self.poll_messages()
                
                if not messages:
                    logger.info("No messages received, continuing to poll...")
                    continue
                
                logger.info(f"Received {len(messages)} message(s)")
                
                for message in messages:
                    self.process_message(message)
                    
            except KeyboardInterrupt:
                logger.info("Received interrupt signal, stopping worker...")
                self.stop()
            except Exception as e:
                logger.error(f"Unexpected error in worker loop: {e}")
                time.sleep(5)

    def stop(self):
        self.running = False
        logger.info("SQS worker stopped")


class BatchSQSWorker(SQSWorker):
    def __init__(self, *args, batch_size: int = 10, **kwargs):
        super().__init__(*args, **kwargs)
        self.batch_size = batch_size

    def process_batch(self, messages: list) -> Dict[str, int]:
        results = {'success': 0, 'failed': 0}
        
        for message in messages:
            if self.process_message(message):
                results['success'] += 1
            else:
                results['failed'] += 1
        
        return results

    def start(self):
        self.running = True
        logger.info(f"Starting batch SQS worker for queue: {self.queue_url}")
        
        while self.running:
            try:
                messages = self.poll_messages()
                
                if not messages:
                    logger.info("No messages received, continuing to poll...")
                    continue
                
                logger.info(f"Received {len(messages)} message(s) for batch processing")
                
                results = self.process_batch(messages)
                logger.info(f"Batch results - Success: {results['success']}, Failed: {results['failed']}")
                
            except KeyboardInterrupt:
                logger.info("Received interrupt signal, stopping worker...")
                self.stop()
            except Exception as e:
                logger.error(f"Unexpected error in worker loop: {e}")
                time.sleep(5)


class PrioritySQSWorker(SQSWorker):
    def process_message(self, message: Dict[str, Any]) -> bool:
        parsed_data = self.parse_message(message)
        if not parsed_data:
            return False
        
        priority = parsed_data.get('priority', 'normal')
        
        if priority == 'high':
            logger.info(f"Processing HIGH priority message: {message.get('MessageId')}")
        elif priority == 'low':
            logger.info(f"Processing LOW priority message: {message.get('MessageId')}")
        
        return super().process_message(message)


